<script setup lang="ts">
import {computed,onMounted,ref} from 'vue';import {CopyDocument,Plus} from '@element-plus/icons-vue';import {ElMessage} from 'element-plus';import {useMerchantStore} from '../stores/merchant';const props=defineProps<{mode:'topups'|'settlements'}>();const store=useMerchantStore();const dialog=ref(false);const submitting=ref(false);const amount=ref('250000.00');const reference=ref(`PORTAL-${Date.now()}`);const phone=ref('');const expectedName=ref('');const reason=ref('');const title=computed(()=>props.mode==='topups'?'Top up liquidity':'Settlements');const isTopup=computed(()=>props.mode==='topups');const demoTopups=[{ref:'TOP-22081',amount:'ETB 250,000.00',status:'success',destination:'Shared liquidity',time:'08 Jul · 10:21'}];const demoSettlements=[{ref:'SET-11804',amount:'ETB 500,000.00',status:'pending',destination:'Telebirr · 09•••5512',time:'08 Jul · 09:04'}];const rows=computed(()=>store.demoMode?(isTopup.value?demoTopups:demoSettlements):isTopup.value?store.transactions.filter(item=>item.customer_id.startsWith('merchant-topup:')).map(item=>({ref:item.reference,amount:`ETB ${item.amount}`,status:item.p2p_status,destination:'Merchant liquidity',time:new Date(item.created_at).toLocaleString()})):store.settlements.map(item=>({ref:item.reference,amount:`ETB ${item.amount}`,status:item.status,destination:`Telebirr · ${item.destination_phone_masked}`,time:new Date(item.requested_at).toLocaleString()})));onMounted(()=>{store.loadTransactions();store.loadSettlements()});function copy(){navigator.clipboard?.writeText(phone.value);ElMessage.success('Number copied')}async function submit(){if(store.demoMode){dialog.value=false;return}submitting.value=true;try{if(isTopup.value){const result=await store.createTopup({tx_ref:reference.value,amount:amount.value,first_name:store.identity?.merchant.name??'Merchant',phone_number:phone.value});window.location.assign(result.checkout_url)}else{await store.createSettlement({reference:reference.value,account_number:phone.value,expected_name:expectedName.value,amount:amount.value,metadata:{reason:reason.value}});ElMessage.success('Settlement submitted for platform approval');dialog.value=false}}catch(error){ElMessage.error(error instanceof Error?error.message:'Request failed')}finally{submitting.value=false}}</script>
<template><div class="page"><div class="page-heading"><div><p class="eyebrow">Merchant liquidity</p><h1>{{title}}</h1><span class="muted">{{isTopup?'Add funds through a timed Telebirr intent.':'Request an approved Telebirr settlement from your ledger.'}}</span></div><el-button type="primary" :icon="Plus" @click="dialog=true">{{isTopup?'Create top-up':'Request settlement'}}</el-button></div>
<section class="grid grid-2 overview"><article class="panel"><span>{{isTopup?'Available ledger':'Available to settle'}}</span><strong>ETB {{store.summary.available}}</strong><small>Merchant-scoped immutable ledger</small></article><article class="panel"><span>{{isTopup?'Loaded top-ups':'Loaded settlements'}}</span><strong>{{rows.length}}</strong><small>Current {{store.environment}} environment</small></article></section>
<section class="panel"><div class="panel-head"><div><h2>{{title}} history</h2><span class="muted small">Latest requests and final outcomes</span></div></div><div class="table-wrap"><el-table :data="rows"><el-table-column prop="ref" label="Reference" min-width="150"/><el-table-column label="Amount" width="170"><template #default="s"><b class="amount">{{s.row.amount}}</b></template></el-table-column><el-table-column prop="destination" :label="isTopup?'Allocation':'Destination'" min-width="190"/><el-table-column label="Status" width="120"><template #default="s"><span :class="`status status-${s.row.status}`">{{s.row.status}}</span></template></el-table-column><el-table-column prop="time" label="Created" width="150"/></el-table></div></section>
<el-dialog v-model="dialog" :title="isTopup?'Create top-up intent':'Request Telebirr settlement'" width="min(520px, 92vw)"><el-alert v-if="!isTopup" title="Platform approval is required" type="info" :closable="false" show-icon/><el-form label-position="top" style="margin-top:16px"><el-form-item label="Amount (ETB)"><el-input v-model="amount" inputmode="decimal"/></el-form-item><el-form-item label="Merchant reference"><el-input v-model="reference" maxlength="128"/></el-form-item><el-form-item :label="isTopup?'Funding Telebirr number':'Approved Telebirr destination'"><el-input v-model="phone" placeholder="09xxxxxxxx or +2519xxxxxxxx"/></el-form-item><el-form-item v-if="!isTopup" label="Expected registered name"><el-input v-model="expectedName"/></el-form-item><el-form-item v-if="!isTopup" label="Reason"><el-input v-model="reason" type="textarea" :rows="3" placeholder="Settlement purpose…"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">Cancel</el-button><el-button type="primary" :loading="submitting" @click="submit">{{isTopup?'Continue to instructions':'Submit for approval'}}</el-button></template></el-dialog></div></template>
<style scoped>.overview{margin-bottom:17px}.overview article{padding:21px}.overview span,.overview strong,.overview small{display:block}.overview span{font-size:9px;color:var(--muted);text-transform:uppercase;font-weight:700}.overview strong{font:800 24px 'Manrope';margin:7px 0}.overview small{font-size:10px;color:var(--muted)}.instruction{text-align:center;background:#f5f5ff;padding:20px;border-radius:12px}.instruction span,.instruction>strong,.instruction small,.instruction>b{display:block}.instruction>strong{font:800 27px 'Manrope';margin:5px}.instruction small{color:var(--muted)}.instruction>b{font:800 20px 'Manrope';margin:8px}.instruction p{font-size:11px}.countdown{padding:9px;background:#fff;border-radius:8px;font-size:11px;color:var(--muted)}.countdown strong{color:var(--primary)}</style>
